import React, { useState, useEffect, useMemo, useRef, useCallback } from 'react';
import { initializeApp } from 'firebase/app';
import { getFirestore, doc, getDoc, setDoc, deleteDoc, onSnapshot, serverTimestamp, runTransaction } from 'firebase/firestore';

// ═══════════════════════════════════════
// V5.6: FIRESTORE SYNC LAYER
// ═══════════════════════════════════════
// Cloud-backed persistence for Tara. Fixes the "refresh-roulette" problem where Tara's Call
// and the engine lock both reset on page reload because they lived only in React refs.
//
// Model: localStorage stays as the fast-paint cache so first paint is instant. Firestore
// is the source of truth — its read overwrites local state ~200-500ms after mount when
// fresher data exists. Writes go to both stores (localStorage immediately, Firestore
// debounced 300-1500ms depending on path).
//
// V5.6.3: SHARED TARA. Previously every userId was its own namespace. Now there is one
// global Tara — every browser, every device, every user who opens the app sees the same
// record, the same memory, the same lock state. Paths are 2-segment globals.
//
// Paths (global, no namespace):
//   state/currentLock     → engine lockedCallRef + Tara snapshot for the active window.
//                           windowId-keyed so a refresh during the same window restores
//                           exactly what was on screen before reload. Stale locks from
//                           previous windows are ignored on restore.
//   scorecards/tara       → Tara's Call W/L/sitouts per window-type.
//   memory/taraCallLog    → array of every call she's made (capped at 500).
//   meta/info             → baselineVersion + lastSeenAt for migration tracking.
//
// NOT cloud-synced (per V5.5b decision — user-trade-driven training stays ephemeral):
//   adaptiveWeights, regimeWeights, tradeLog. These remain in-memory only this session.
//
// Test-mode caveat: Firestore rules are wide open for ~30 days. Lock down in V5.7 with
// proper rules.
const FIREBASE_CONFIG={apiKey:"AIzaSyD8jltDNdmXPE0JolUSX6fXzSQUdsYjLcY",authDomain:"tara-app-ee39d.firebaseapp.com",projectId:"tara-app-ee39d",storageBucket:"tara-app-ee39d.firebasestorage.app",messagingSenderId:"512450573817",appId:"1:512450573817:web:b1659b8f28f894900f7928"};
let _fbApp=null,_fbDb=null;
try{_fbApp=initializeApp(FIREBASE_CONFIG);_fbDb=getFirestore(_fbApp);console.info('[Firestore] init ok — shared Tara, no namespacing');}
catch(e){console.warn('[Firestore] init failed — falling back to localStorage only:',e?.message);}

const _fbDoc=(path)=>{
  if(!_fbDb)return null;
  // V5.6.3: paths are 2-segment globals (collection/doc). One Tara, everyone shares.
  const segs=path.split('/');
  return doc(_fbDb,...segs);
};
// V5.6.1: Cloud sync status — subscribers (React components) get notified on state change.
//   States: 'idle' (no recent activity), 'writing' (debounced or in-flight), 'ok' (last
//   write succeeded), 'error' (last write/read failed). Used for a visible indicator dot.
// V5.6.3: Track active onSnapshot listeners. If listeners > 0, real-time sync is alive
//   and changes from any device propagate within ~1s without refresh. If listeners = 0
//   but Firestore is initialized, something's wrong (rules, network, etc.).
const _cloudSyncListeners=new Set();
let _cloudSyncStatus={state:_fbDb?'idle':'disabled',lastOk:null,lastError:null,writes:0,reads:0,listeners:0};
const _setCloudStatus=(patch)=>{_cloudSyncStatus={..._cloudSyncStatus,...patch};_cloudSyncListeners.forEach(l=>l(_cloudSyncStatus));};
const subscribeCloudStatus=(fn)=>{_cloudSyncListeners.add(fn);fn(_cloudSyncStatus);return()=>_cloudSyncListeners.delete(fn);};

// ── V8.3: CROSS-TAB BROADCAST CHANNEL ────────────────────────────────────────
// Instant cross-tab messaging within the same browser. Eliminates the ~1s wait for
// Firestore round-trip when one tab adds an entry — other tabs see it immediately.
// Backed up by Firestore + RMW writes for cross-device + cross-browser sync.
const _crossTab=(typeof BroadcastChannel!=='undefined')?(()=>{try{return new BroadcastChannel('tara-cross-tab-v1');}catch(_){return null;}})():null;
const broadcastToOtherTabs=(type,payload)=>{
  if(!_crossTab)return;
  try{_crossTab.postMessage({type,payload,t:Date.now()});}catch(_){}
};
const subscribeToOtherTabs=(handler)=>{
  if(!_crossTab)return()=>{};
  const fn=(event)=>{try{handler(event.data);}catch(_){}};
  _crossTab.addEventListener('message',fn);
  return()=>{try{_crossTab.removeEventListener('message',fn);}catch(_){}};
};
// V8.3: Tab heartbeat — each tab broadcasts a heartbeat every 5s so peers can detect
//   how many tabs are active. Stored in module-level Map keyed by tabId.
const _tabId=Math.random().toString(36).slice(2,10)+'-'+Date.now().toString(36);
const _peerTabs=new Map(); // tabId → {lastSeen, currentAsset}
let _peerListeners=new Set();
const _notifyPeerListeners=()=>{_peerListeners.forEach(fn=>{try{fn(Array.from(_peerTabs.entries()));}catch(_){}});};
if(_crossTab){
  _crossTab.addEventListener('message',(event)=>{
    const d=event.data;
    if(!d||d.type!=='heartbeat')return;
    const{tabId,currentAsset}=d.payload||{};
    if(!tabId||tabId===_tabId)return;
    _peerTabs.set(tabId,{lastSeen:Date.now(),currentAsset});
    _notifyPeerListeners();
  });
  // GC peers that haven't been heard from in 15s
  setInterval(()=>{
    const now=Date.now();
    let changed=false;
    for(const[id,info]of _peerTabs.entries()){
      if(now-info.lastSeen>15000){_peerTabs.delete(id);changed=true;}
    }
    if(changed)_notifyPeerListeners();
  },5000);
}
const subscribeToPeerTabs=(fn)=>{_peerListeners.add(fn);fn(Array.from(_peerTabs.entries()));return()=>_peerListeners.delete(fn);};
const getCurrentTabId=()=>_tabId;

const cloudRead=async(path)=>{
  const ref=_fbDoc(path);if(!ref)return null;
  try{
    const s=await getDoc(ref);
    _setCloudStatus({state:'ok',lastOk:Date.now(),reads:_cloudSyncStatus.reads+1});
    return s.exists()?s.data():null;
  }catch(e){
    console.warn('[Firestore read failed]',path,e?.message);
    _setCloudStatus({state:'error',lastError:{path,message:e?.message,at:Date.now()}});
    return null;
  }
};
const cloudWrite=async(path,data)=>{
  const ref=_fbDoc(path);if(!ref)return false;
  _setCloudStatus({state:'writing'});
  try{
    await setDoc(ref,{...data,_updatedAt:serverTimestamp()});
    _setCloudStatus({state:'ok',lastOk:Date.now(),writes:_cloudSyncStatus.writes+1});
    return true;
  }catch(e){
    console.warn('[Firestore write failed]',path,e?.message);
    _setCloudStatus({state:'error',lastError:{path,message:e?.message,at:Date.now()}});
    return false;
  }
};
const cloudDelete=async(path)=>{
  const ref=_fbDoc(path);if(!ref)return false;
  try{await deleteDoc(ref);_setCloudStatus({state:'ok',lastOk:Date.now(),writes:_cloudSyncStatus.writes+1});return true;}
  catch(e){console.warn('[Firestore delete failed]',path,e?.message);_setCloudStatus({state:'error',lastError:{path,message:e?.message,at:Date.now()}});return false;}
};
// V5.6.2: Real-time listener — fires once with current cloud value, then again on every
//   change from any connected client. This is what makes cross-device sync actually work:
//   Device A writes, Device B's listener fires within ~1s, B's UI updates without refresh.
//   Returns an unsubscribe function the caller stores in a useEffect cleanup.
// V5.6.3: Tracks active listener count in sync status — so the badge can show whether
//   real-time sync is actually established vs. just one-shot reads happening.
const cloudWatch=(path,callback)=>{
  const ref=_fbDoc(path);
  if(!ref){callback(null,'disabled');return()=>{};}
  _setCloudStatus({listeners:_cloudSyncStatus.listeners+1});
  const unsub=onSnapshot(ref,
    (snap)=>{
      _setCloudStatus({state:'ok',lastOk:Date.now(),reads:_cloudSyncStatus.reads+1});
      callback(snap.exists()?snap.data():null,'ok');
    },
    (err)=>{
      console.warn('[Firestore listen failed]',path,err?.message);
      _setCloudStatus({state:'error',lastError:{path,message:err?.message,at:Date.now()}});
      callback(null,'error');
    }
  );
  return()=>{
    _setCloudStatus({listeners:Math.max(0,_cloudSyncStatus.listeners-1)});
    unsub();
  };
};
// Coalesces rapid updates per-path into a single Firestore write (saves quota + bandwidth).
const _writeQueue=new Map();
// V8.1: Track latest pending data per path so we can synchronously flush on tab close.
//   Map of path → most recent data, separate from the timeout map.
const _writePending=new Map();
const cloudWriteDebounced=(path,data,delayMs=300)=>{
  if(_writeQueue.has(path))clearTimeout(_writeQueue.get(path));
  _writePending.set(path,data);
  const tid=setTimeout(()=>{
    cloudWrite(path,data);
    _writeQueue.delete(path);
    _writePending.delete(path);
  },delayMs);
  _writeQueue.set(path,tid);
};
// V8.1: Synchronously fire all pending debounced writes. Called on pagehide/beforeunload
//   so trades made just before tab close don't get lost in the 300ms debounce window.
//   Returns the count of writes flushed.
const cloudFlushAll=()=>{
  let flushed=0;
  for(const[path,tid]of _writeQueue.entries()){
    clearTimeout(tid);
    const data=_writePending.get(path);
    if(data!=null){
      // Fire-and-forget — no await. Modern browsers respect the in-flight fetch
      //   on pagehide for a brief grace period. Firestore writes use fetch internally.
      try{cloudWrite(path,data);flushed++;}catch(_){}
    }
  }
  _writeQueue.clear();
  _writePending.clear();
  return flushed;
};
// V8.1: Wire flush to tab visibility change events. Browsers fire pagehide reliably
//   on real tab close + navigation; visibilitychange covers tab switch/minimize.
// V8.3: Now also drains RMW queue (best-effort; local-only write if cloud read can't complete).
//   The actual flush function combining both is defined below the RMW helpers.

// ── V8.3: READ-MODIFY-WRITE DEBOUNCED HELPER ────────────────────────────────
// Solves the multi-tab last-write-wins clobbering problem. When timer fires:
//   1. Open Firestore transaction — atomic read+write with auto-retry on conflict
//   2. Inside tx: read current cloud state, call mergeFn(cloudData, currentLocalData),
//      tx.set() the merged result. If another tab wrote between our read and write,
//      Firestore aborts our tx and retries our handler — guaranteeing serialization.
// getLocalData is a function (not a value) so we get the freshest local state when
// the timer fires, even if state changed during the debounce window.
// mergeFn returns null to skip the write entirely (e.g., no changes after merge).
const _writeQueueRMW=new Map();
const _writePendingRMW=new Map();
const cloudWriteDebouncedRMW=(path,getLocalData,mergeFn,delayMs=400)=>{
  if(_writeQueueRMW.has(path))clearTimeout(_writeQueueRMW.get(path));
  _writePendingRMW.set(path,{getLocalData,mergeFn});
  const tid=setTimeout(async()=>{
    _writeQueueRMW.delete(path);
    _writePendingRMW.delete(path);
    const ref=_fbDoc(path);
    if(!ref||!_fbDb){
      // Firestore not initialized — best-effort write of local data without merge
      try{
        const localData=getLocalData();
        const merged=mergeFn(null,localData);
        if(merged!=null)await cloudWrite(path,merged);
      }catch(_){}
      return;
    }
    try{
      _setCloudStatus({state:'writing'});
      // True atomic transaction. Firestore auto-retries (up to 5x by default) if
      //   another tab/device modifies the doc between our read and write inside the tx.
      //   This guarantees that concurrent writes serialize — no clobbering possible.
      await runTransaction(_fbDb,async(tx)=>{
        const snap=await tx.get(ref);
        const cloudData=snap.exists()?snap.data():null;
        const localData=getLocalData();
        const merged=mergeFn(cloudData,localData);
        if(merged!=null){
          tx.set(ref,{...merged,_updatedAt:serverTimestamp()});
        }
      });
      _setCloudStatus({state:'ok',lastOk:Date.now(),writes:_cloudSyncStatus.writes+1});
    }catch(e){
      try{console.warn('[V8.3] RMW transaction failed',path,e?.message);}catch(_){}
      _setCloudStatus({state:'error',lastError:{path,message:e?.message,at:Date.now()}});
    }
  },delayMs);
  _writeQueueRMW.set(path,tid);
};
// V8.3: Force-flush all RMW writes synchronously on tab close. Cloud reads can't
//   complete in pagehide grace window, so we write local data without merge — better
//   than losing the write entirely. cloudWatch on other tabs will re-merge.
const _cloudFlushAllRMW=()=>{
  let flushed=0;
  for(const[path,tid]of _writeQueueRMW.entries()){
    clearTimeout(tid);
    const entry=_writePendingRMW.get(path);
    if(entry&&typeof entry.getLocalData==='function'){
      try{
        const localData=entry.getLocalData();
        // Call merge with null cloudData — caller's mergeFn handles this case
        const merged=entry.mergeFn(null,localData);
        if(merged!=null){cloudWrite(path,merged);flushed++;}
      }catch(_){}
    }
  }
  _writeQueueRMW.clear();
  _writePendingRMW.clear();
  return flushed;
};
// Combined flush — called on tab close
const cloudFlushAllCombined=()=>cloudFlushAll()+_cloudFlushAllRMW();
if(typeof window!=='undefined'){
  const _onLeave=()=>{try{cloudFlushAllCombined();}catch(_){}};
  window.addEventListener('pagehide',_onLeave);
  window.addEventListener('beforeunload',_onLeave);
  window.addEventListener('visibilitychange',()=>{
    if(document.visibilityState==='hidden')_onLeave();
  });
}
// Deterministic ID for the current trading window (UTC ISO of window-open boundary).
// Refresh during the same window → same ID → restore the same lock.
const computeWindowId=(windowType)=>{
  const winMs=windowType==='15m'?900000:300000;
  const bucketMs=Math.floor(Date.now()/winMs)*winMs;
  return `${windowType}-${new Date(bucketMs).toISOString()}`;
};

