// HOOKS
// ═══════════════════════════════════════
const useVelocity=(tickH,price,target)=>{const ref=useRef({v1s:0,v5s:0,v15s:0,v30s:0,accel:0,jerk:0,peakPnL:0,troughPnL:0,pnlSlope:0});const pnlH=useRef([]);useEffect(()=>{const iv=setInterval(()=>{if(!price||!target)return;const now=Date.now(),ticks=tickH.current||[];const ga=(ms)=>{const r=ticks.filter(t=>Math.abs((now-t.time)-ms)<2000);return r.length>0?r.reduce((a,b)=>a+b.p,0)/r.length:null;};const p1=ga(1000),p5=ga(5000),p15=ga(15000),p30=ga(30000);const v1s=p1?(price-p1):0,v5s=p5?(price-p5)/5:0,v15s=p15?(price-p15)/15:0,v30s=p30?(price-p30)/30:0;const cpnl=target>0?((price-target)/target)*10000:0;pnlH.current.push({pnl:cpnl,time:now});pnlH.current=pnlH.current.filter(p=>now-p.time<120000);const peakPnL=Math.max(...pnlH.current.map(p=>p.pnl),cpnl);const troughPnL=Math.min(...pnlH.current.map(p=>p.pnl),cpnl);const recent=pnlH.current.filter(p=>now-p.time<10000);const pnlSlope=recent.length>=3?recent[recent.length-1].pnl-recent[0].pnl:0;ref.current={v1s,v5s,v15s,v30s,accel:v5s-v15s,jerk:v1s-v5s,peakPnL,troughPnL,pnlSlope};},500);return()=>clearInterval(iv);},[price,target]);return ref;};

const useGlobalTape=(asset)=>{
  const tapeRef=useRef({coinbase:{buys:0,sells:0},binanceFutures:{buys:0,sells:0},bybit:{buys:0,sells:0},globalBuys:0,globalSells:0,globalImbalance:1,cbFlow:0,bnFlow:0,byFlow:0,divergence:0,whaleAlerts:[],binancePrice:0,bybitPrice:0});
  const ticksRef=useRef([]);
  const streakRef=useRef({dir:null,count:0,startTime:Date.now(),totalUSD:0,trades:[]}); // consecutive whale prints
  const flowHistoryRef=useRef([]); // 5-min rolling net delta history for trend
  const[whaleLog,setWhaleLog]=useState([]);
  const[globalFlow,setGlobalFlow]=useState({imbalance:1,divergence:0,whaleAlert:null,feeds:0,deltaUSD:0});
  const[flowSignal,setFlowSignal]=useState({
    score:0,           // 0-100 actionable score
    label:'NEUTRAL',   // NOISE | EMERGING | STRONG | CONVICTION
    streakDir:null,    // 'BUY' | 'SELL' | null
    streakCount:0,     // consecutive whale prints same direction
    streakDuration:0,  // seconds
    streakUSD:0,       // total USD in streak
    oiContext:'',      // human-readable OI interpretation
    divergence:false,  // spot vs futures diverging
    netDelta30s:0,     // net buy-sell USD in last 30s
    netDelta90s:0,     // net buy-sell USD in last 90s
    trend:'flat',      // '↑ accelerating' | '↓ fading' | 'flat'
  });

  // V3.1: Sliding-window buy/sell tape at 5s / 15s / 30s / 60s.
  //       Each window: {buys, sells, total, buyPct, side}
  //       Lets the UI show buying-vs-selling pressure and whether it's accelerating
  //       (compare 60s → 30s → 15s → 5s pattern). Updates with the same 1s aggregation tick.
  const[tapeWindows,setTapeWindows]=useState({
    w5:{buys:0,sells:0,buyPct:50,side:null},
    w15:{buys:0,sells:0,buyPct:50,side:null},
    w30:{buys:0,sells:0,buyPct:50,side:null},
    w60:{buys:0,sells:0,buyPct:50,side:null},
  });

  useEffect(()=>{
    if(typeof window==='undefined')return;
    let wsBN=null,wsBY=null,feedCount=0;

    const processWhalePrint=(alert)=>{
      const sk=streakRef.current;
      const now=Date.now();
      const streakWindow=120000; // 2 min streak window
      if(sk.dir===alert.side&&(now-sk.startTime)<streakWindow){
        // Same direction — extend streak
        sk.count++;sk.totalUSD+=alert.usd;sk.trades.push(alert);
      } else {
        // Direction changed or streak expired — reset
        sk.dir=alert.side;sk.count=1;sk.startTime=now;sk.totalUSD=alert.usd;sk.trades=[alert];
      }
      streakRef.current=sk;
    };

    try{
      const _cfg=ASSET_CONFIG[asset]||ASSET_CONFIG.BTC;
      const _bnSym=String(_cfg.binance||'BTCUSDT').toLowerCase();
      const _whaleFloor=Number(_cfg.whaleFloor)||100000;
      wsBN=new WebSocket(`wss://fstream.binance.com/ws/${_bnSym}@aggTrade`);
      wsBN.onopen=()=>{feedCount++;};
      wsBN.onmessage=(e)=>{
        try{
          const d=JSON.parse(e.data);
          const price=parseFloat(d.p),qty=parseFloat(d.q),usd=price*qty,isBuy=!d.m,now=Date.now();
          ticksRef.current.push({p:price,s:qty,usd,t:isBuy?'B':'S',src:'bn',time:now});
          tapeRef.current.binancePrice=price;
          if(usd>_whaleFloor){
            const alert={src:'Binance',side:isBuy?'BUY':'SELL',size:qty,usd,price,time:now};
            tapeRef.current.whaleAlerts.push(alert);
            tapeRef.current.whaleAlerts=tapeRef.current.whaleAlerts.slice(-20);
            processWhalePrint(alert);
            setWhaleLog(prev=>[alert,...prev].slice(0,30));
          }
        }catch(er){}
      };
    }catch(e){}

    try{
      const _cfg2=ASSET_CONFIG[asset]||ASSET_CONFIG.BTC;
      const _bySym=_cfg2.bybit||'BTCUSDT';
      const _whaleFloor2=Number(_cfg2.whaleFloor)||100000;
      const _topic=`publicTrade.${_bySym}`;
      wsBY=new WebSocket('wss://stream.bybit.com/v5/public/linear');
      wsBY.onopen=()=>{feedCount++;wsBY.send(JSON.stringify({op:'subscribe',args:[_topic]}));};
      wsBY.onmessage=(e)=>{
        try{
          const msg=JSON.parse(e.data);
          if(msg.topic===_topic&&msg.data){
            msg.data.forEach(trade=>{
              const price=parseFloat(trade.p),qty=parseFloat(trade.v),usd=price*qty,isBuy=trade.S==='Buy',now=Date.now();
              ticksRef.current.push({p:price,s:qty,usd,t:isBuy?'B':'S',src:'by',time:now});
              tapeRef.current.bybitPrice=price;
              if(usd>_whaleFloor2){
                const alert={src:'Bybit',side:isBuy?'BUY':'SELL',size:qty,usd,price,time:now};
                tapeRef.current.whaleAlerts.push(alert);
                tapeRef.current.whaleAlerts=tapeRef.current.whaleAlerts.slice(-20);
                processWhalePrint(alert);
                setWhaleLog(prev=>[alert,...prev].slice(0,30));
              }
            });
          }
        }catch(er){}
      };
    }catch(e){}

    const aggIv=setInterval(()=>{
      const now=Date.now();
      ticksRef.current=ticksRef.current.filter(t=>now-t.time<90000); // keep 90s

      // Split into time windows
      let cbB=0,cbS=0,bnB=0,bnS=0,byB=0,byS=0;
      let net30=0,net90=0;
      ticksRef.current.forEach(t=>{
        const u=t.usd||(t.s*t.p);
        const sign=t.t==='B'?1:-1;
        if(now-t.time<30000)net30+=u*sign;
        if(now-t.time<90000)net90+=u*sign;
        if(t.src==='cb'){if(t.t==='B')cbB+=u;else cbS+=u;}
        else if(t.src==='bn'){if(t.t==='B')bnB+=u;else bnS+=u;}
        else if(t.src==='by'){if(t.t==='B')byB+=u;else byS+=u;}
      });
      const gB=cbB+bnB+byB,gS=cbS+bnS+byS;
      const gI=gS===0?(gB>0?2:1):gB/gS;
      const cbF=(cbB+cbS)>0?(cbB-cbS)/(cbB+cbS):0;
      const bnF=(bnB+bnS)>0?(bnB-bnS)/(bnB+bnS):0;
      const byF=(byB+byS)>0?(byB-byS)/(byB+byS):0;
      // Spot vs futures divergence: cbF opposite to (bnF+byF)/2
      const futuresFlow=(bnF+byF)/2;
      const div=(gB+gS)>50000&&Math.abs(cbF)>0.2&&Math.abs(futuresFlow)>0.2&&Math.sign(cbF)!==Math.sign(futuresFlow)?Math.sign(futuresFlow):-0;
      tapeRef.current={...tapeRef.current,coinbase:{buys:cbB,sells:cbS},binanceFutures:{buys:bnB,sells:bnS},bybit:{buys:byB,sells:byS},globalBuys:gB,globalSells:gS,globalImbalance:gI,cbFlow:cbF,bnFlow:bnF,byFlow:byF,divergence:div};
      const rW=tapeRef.current.whaleAlerts.find(w=>now-w.time<5000);
      setGlobalFlow({imbalance:gI,divergence:div,whaleAlert:rW||null,feeds:feedCount,deltaUSD:gB-gS});

      // V3.1: Sliding-window buy/sell pressure at 5s / 15s / 30s / 60s.
      //       Each window aggregates buy/sell USD across all venues (Coinbase + Binance + Bybit).
      //       Designed for the UI tape strip — lets users see acceleration/deceleration of flow.
      const _bucket=(seconds)=>{
        let b=0,s=0;
        const cutoff=now-seconds*1000;
        ticksRef.current.forEach(t=>{
          if(t.time<cutoff)return;
          const u=t.usd||(t.s*t.p);
          if(t.t==='B')b+=u;else s+=u;
        });
        const total=b+s;
        const buyPct=total>0?(b/total)*100:50;
        const side=total<1000?null:(buyPct>=55?'BUY':buyPct<=45?'SELL':null);
        return{buys:b,sells:s,buyPct,side};
      };
      setTapeWindows({
        w5:_bucket(5),
        w15:_bucket(15),
        w30:_bucket(30),
        w60:_bucket(60),
      });

      // ── FLOW SIGNAL COMPUTATION ─────────────────────────────────────────
      const sk=streakRef.current;
      const streakAge=(now-sk.startTime)/1000;
      const isStreakFresh=sk.count>=1&&streakAge<120;

      // Expire streak if no activity for 2 min
      if(streakAge>120){streakRef.current={dir:null,count:0,startTime:now,totalUSD:0,trades:[]};}

      // Net delta trend: compare 30s vs 90s (is flow accelerating or fading?)
      let trend='flat';
      if(Math.abs(net30)>10000&&Math.abs(net90)>10000){
        const rate30=net30/30,rate90=net90/90;
        if(Math.sign(rate30)===Math.sign(rate90)&&Math.abs(rate30)>Math.abs(rate90)*1.3)trend=`${net30>0?'↑':'↓'} accel`;
        else if(Math.sign(rate30)===Math.sign(rate90)&&Math.abs(rate30)<Math.abs(rate90)*0.7)trend=`${net30>0?'↑':'↓'} fading`;
        else trend=`${net30>0?'↑':'↓'} steady`;
      }

      // Score components (0-100)
      const imbalanceScore=Math.min(40,Math.abs(gI-1)*30); // flow pressure
      const streakScore=isStreakFresh?Math.min(40,(sk.count-1)*12):0; // streak conviction
      const accelScore=trend.includes('accel')?15:trend.includes('fading')?-10:0;
      const divPenalty=div!==0?-20:0; // divergence = basis trade = not directional
      const rawScore=Math.max(0,Math.min(100,imbalanceScore+streakScore+accelScore+divPenalty));

      const label=rawScore<25?'NOISE':rawScore<50?'EMERGING':rawScore<75?'STRONG':'CONVICTION';
      const isDivergence=div!==0;
      const streakDir=isStreakFresh?sk.dir:null;

      setFlowSignal({
        score:rawScore,label,streakDir,
        streakCount:isStreakFresh?sk.count:0,
        streakDuration:isStreakFresh?Math.round(streakAge):0,
        streakUSD:isStreakFresh?sk.totalUSD:0,
        divergence:isDivergence,
        netDelta30s:net30,netDelta90s:net90,trend,
        oiContext:'', // filled by component using bloomberg
      });
    },1000);

    return()=>{
      clearInterval(aggIv);
      if(wsBN?.readyState===1)wsBN.close();
      if(wsBY?.readyState===1)wsBY.close();
    };
  },[asset]);

  return{tapeRef,globalFlow,ticksRef,whaleLog,flowSignal,tapeWindows};
};

// ── V8.1: useMovementRisk — REAL-TIME RISK PULSE ─────────────────────────────
// Combines vol acceleration, volume spikes, tape imbalance, whale density into a 0-100
// risk score. Updates every 2s. All inputs are existing refs — no new data fetches.
// Returns: { level: 'CALM'|'NORMAL'|'ELEVATED'|'EXTREME', score: 0-100,
//            dirBias: 'UP'|'DOWN'|null, reasons: [{tag, weight}], predictive: '...' }
const useMovementRisk=(velocityRef,tapeRef,ticksRef,whaleLog,regimeRef)=>{
  const ref=useRef({level:'CALM',score:0,dirBias:null,reasons:[],predictive:null});
  const baselineRef=useRef({accel:0.5,volume:0,sampleAt:0});
  const[snapshot,setSnapshot]=React.useState({level:'CALM',score:0,dirBias:null,reasons:[],predictive:null});
  React.useEffect(()=>{
    const tick=()=>{
      try{
        const now=Date.now();
        const v=velocityRef?.current||{};
        const tape=tapeRef?.current||{};
        const ticks=ticksRef?.current||[];
        const whales=whaleLog||[];
        let score=0;
        const reasons=[];
        let dirBias=null;
        // ── Vol acceleration vs rolling baseline ──
        // Baseline = exponentially-weighted moving avg of |accel|. Updated each tick at 0.05 weight.
        const _accel=Math.abs(Number(v.accel)||0);
        if(now-baselineRef.current.sampleAt>1500){
          baselineRef.current.accel=baselineRef.current.accel*0.95+_accel*0.05;
          baselineRef.current.sampleAt=now;
        }
        const _accelBase=Math.max(0.5,baselineRef.current.accel);
        const _accelRatio=_accel/_accelBase;
        if(_accelRatio>=2.5){
          score+=30;
          reasons.push({tag:`accel ${_accelRatio.toFixed(1)}x baseline`,weight:30});
        } else if(_accelRatio>=1.8){
          score+=18;
          reasons.push({tag:`accel ${_accelRatio.toFixed(1)}x`,weight:18});
        } else if(_accelRatio<=0.4){
          // Compression: low vol relative to baseline. Often precedes breakouts.
          score+=10;
          reasons.push({tag:`compressed ${_accelRatio.toFixed(2)}x`,weight:10});
        }
        // ── Volume spike: last 30s vs last 5min average ──
        const _last30s=ticks.filter(t=>now-t.time<30000);
        const _last5min=ticks.filter(t=>now-t.time<300000);
        if(_last30s.length>=5&&_last5min.length>=20){
          const _vol30=_last30s.reduce((s,t)=>s+(t.usd||t.sz||1),0);
          const _vol5min=_last5min.reduce((s,t)=>s+(t.usd||t.sz||1),0);
          const _per30=_vol30;
          const _avg30=_vol5min/(300/30); // expected 30s slice of 5min total
          if(_avg30>0){
            const _volRatio=_per30/_avg30;
            if(_volRatio>=3){
              score+=25;
              reasons.push({tag:`volume spike ${_volRatio.toFixed(1)}x`,weight:25});
            } else if(_volRatio>=2){
              score+=15;
              reasons.push({tag:`volume ${_volRatio.toFixed(1)}x avg`,weight:15});
            }
          }
        }
        // ── Tape imbalance ──
        const _imb=Number(tape.globalImbalance)||1;
        if(_imb>=3){
          score+=20;
          dirBias='UP';
          reasons.push({tag:`buy pressure ${_imb.toFixed(1)}x`,weight:20});
        } else if(_imb<=0.33){
          score+=20;
          dirBias='DOWN';
          reasons.push({tag:`sell pressure ${(1/_imb).toFixed(1)}x`,weight:20});
        } else if(_imb>=2){
          score+=10;
          dirBias='UP';
          reasons.push({tag:`buy lean ${_imb.toFixed(1)}x`,weight:10});
        } else if(_imb<=0.5){
          score+=10;
          dirBias='DOWN';
          reasons.push({tag:`sell lean ${(1/_imb).toFixed(1)}x`,weight:10});
        }
        // ── Whale density: prints in last 60s vs last 10min baseline ──
        const _whale60s=whales.filter(w=>now-w.time<60000);
        const _whale10min=whales.filter(w=>now-w.time<600000);
        if(_whale60s.length>=2){
          const _per60=_whale60s.length;
          const _avg60=_whale10min.length/(600/60);
          if(_avg60>0&&_per60/_avg60>=2.5){
            score+=15;
            reasons.push({tag:`${_per60} whales in 60s`,weight:15});
            // Whale directional cluster
            const _whaleBuys=_whale60s.filter(w=>w.side==='BUY').length;
            const _whaleSells=_whale60s.filter(w=>w.side==='SELL').length;
            if(_whaleBuys>=_whaleSells*2)dirBias=dirBias||'UP';
            else if(_whaleSells>=_whaleBuys*2)dirBias=dirBias||'DOWN';
          }
        }
        // ── Choppy regime amplifier ──
        const regime=regimeRef?.current||null;
        if((regime==='RANGE_BOUND'||regime==='CHOP'||regime==='RANGE'||regime==='RANGE-CHOP')&&score>=40){
          score+=8;
          reasons.push({tag:'chop amplifies risk',weight:8});
        }
        // ── Predictive readout ──
        let predictive=null;
        if(score>=60&&dirBias){
          predictive=`${dirBias} move likely next 30-60s`;
        } else if(_accelRatio<=0.5&&_imb>1.5&&_imb<2&&score<40){
          predictive='compressed — breakout watch';
        } else if(score>=70){
          predictive='extreme conditions — stand back';
        } else if(score<=15){
          predictive='calm — favorable for normal positions';
        }
        // ── Level classification ──
        score=Math.min(100,Math.max(0,score));
        const level=score<20?'CALM':score<45?'NORMAL':score<70?'ELEVATED':'EXTREME';
        const next={level,score:Math.round(score),dirBias,reasons,predictive};
        ref.current=next;
        setSnapshot(next);
      }catch(_){}
    };
    tick();
    const iv=setInterval(tick,2000);
    return()=>clearInterval(iv);
  },[velocityRef,tapeRef,ticksRef,whaleLog,regimeRef]);
  return snapshot;
};

// ── V8.5: WITHIN-WINDOW PATH METRICS ─────────────────────────────────────────
// Computes how the trade's price path behaved between entry and close. Run at trade
// resolution (inside the rollover handler) using the window-tracking refs that
// already exist + the trade's direction and strike.
//
// Returns:
//   maxFavorableExcursionBps   — best you ever were vs strike (signed: + = favorable)
//   maxAdverseExcursionBps     — worst you ever were vs strike (signed: - = adverse)
//   peakClockSec               — clockSeconds when MFE was hit
//   troughClockSec             — clockSeconds when MAE was hit
//   last60sDriftBps            — net price move in the final 60s of the window
//   reversalFromPeak           — true if MFE was meaningfully positive then ended unfavorable
//   peakPosition               — 'EARLY' | 'MID' | 'LATE' bucketing of when MFE happened
const computePathMetrics=({dir,strike,windowHigh,windowLow,windowHighTime,windowLowTime,windowOpenTime,closeTime,ticksAtClose,closingPrice})=>{
  const out={
    maxFavorableExcursionBps:null,
    maxAdverseExcursionBps:null,
    peakClockSec:null,
    troughClockSec:null,
    last60sDriftBps:null,
    reversalFromPeak:false,
    peakPosition:null,
  };
  if(!dir||!strike||strike<=0)return out;
  if(!windowHigh||!windowLow||!closeTime||!windowOpenTime)return out;
  const totalWindowMs=closeTime-windowOpenTime;
  if(totalWindowMs<=0)return out;
  // For UP positions: profitable when price > strike. So MFE = max(price)-strike, MAE = min(price)-strike.
  // For DOWN positions: profitable when price < strike. So MFE = strike-min(price), MAE = strike-max(price).
  const sign=dir==='UP'?1:-1;
  const _mfePrice=sign>0?windowHigh:windowLow;
  const _maePrice=sign>0?windowLow:windowHigh;
  const _mfeTime=sign>0?windowHighTime:windowLowTime;
  const _maeTime=sign>0?windowLowTime:windowHighTime;
  out.maxFavorableExcursionBps=Math.round(((_mfePrice-strike)/strike)*10000*sign);
  out.maxAdverseExcursionBps=Math.round(((_maePrice-strike)/strike)*10000*sign);
  // Peak/trough times — clockSeconds REMAINING when the extreme was hit (matches lock-clock convention)
  const _winSec=Math.round(totalWindowMs/1000);
  if(_mfeTime){
    const _elapsedMs=_mfeTime-windowOpenTime;
    out.peakClockSec=Math.max(0,_winSec-Math.round(_elapsedMs/1000));
  }
  if(_maeTime){
    const _elapsedMs=_maeTime-windowOpenTime;
    out.troughClockSec=Math.max(0,_winSec-Math.round(_elapsedMs/1000));
  }
  // Peak position bucket — when did the favorable extreme happen relative to total window time?
  if(_mfeTime){
    const _mfeFrac=(_mfeTime-windowOpenTime)/totalWindowMs;
    out.peakPosition=_mfeFrac<0.33?'EARLY':_mfeFrac<0.67?'MID':'LATE';
  }
  // Last 60s drift — find the tick from 60s before close, compute % move from there to close
  if(Array.isArray(ticksAtClose)&&ticksAtClose.length>0&&closingPrice>0){
    const _t60ago=closeTime-60000;
    const _olderTick=ticksAtClose.filter(t=>t&&t.time&&t.time<=_t60ago).slice(-1)[0];
    if(_olderTick){
      // tickHistoryRef stores price as `p`; some other tick sources use `price`
      const _olderPrice=Number(_olderTick.p)||Number(_olderTick.price)||0;
      if(_olderPrice>0){
        out.last60sDriftBps=Math.round(((closingPrice-_olderPrice)/_olderPrice)*10000);
      }
    }
  }
  // Reversal flag — were you meaningfully favorable at any point, but ended up losing?
  // Threshold +5bps favorable is the floor for "real reversal" (anything less is noise).
  const _closingExcBps=Math.round(((closingPrice-strike)/strike)*10000*sign);
  if((out.maxFavorableExcursionBps||0)>=5&&_closingExcBps<0){
    out.reversalFromPeak=true;
  }
  return out;
};

// ── V8.5: LOSS-PATTERN CLASSIFIER ────────────────────────────────────────────
// Takes a resolved LOSS trade with path metrics + whale/macro context and returns
// one of six pattern labels. Used to (a) show user "your most common loss type"
// and (b) skip gradient-descent punishment on shock losses where the signals
// were correct but the world changed.
//
// Categories (mutually exclusive, order matters — first match wins):
//   WHALE_SPIKE      — large whale print >$200K within 60s of reversal/close
//   MACRO_SHOCK      — geoRisk peak ≥0.5 OR major news event during window
//   LATE_REVERSAL    — was favorable in last third, then flipped
//   MID_REVERSAL     — was favorable in middle third, then faded
//   EARLY_PEAK       — was favorable in first third, then sustained loss
//   WRONG_FROM_START — never above water (MFE ≤ 0)
const classifyLossPattern=(trade)=>{
  if(!trade||trade.result!=='LOSS')return null;
  const mfe=trade.maxFavorableExcursionBps;
  const reversed=!!trade.reversalFromPeak;
  const peakPos=trade.peakPosition;
  const last60s=trade.last60sDriftBps;
  // Shock detectors — these override path-pattern even if path looks like reversal,
  // because the cause was external.
  const hasContrayWhale=trade.windowContraryWhaleUsd&&trade.windowContraryWhaleUsd>=200000
    &&trade.windowContraryWhaleClockSec!=null
    &&trade.windowContraryWhaleClockSec<=60; // within last 60s of window
  if(hasContrayWhale)return'WHALE_SPIKE';
  const hadShock=(trade.windowMaxGeoRisk||0)>=0.5||!!trade.windowHadMacroEvent;
  if(hadShock)return'MACRO_SHOCK';
  // Path-based — straightforward bucket from peak position
  if(mfe==null||mfe<=0)return'WRONG_FROM_START';
  // Reversal-flagged path losses
  if(reversed){
    if(peakPos==='LATE')return'LATE_REVERSAL';
    if(peakPos==='MID')return'MID_REVERSAL';
    if(peakPos==='EARLY')return'EARLY_PEAK';
  }
  // Edge case: meaningful MFE but no clean peakPos — fall back on last60s drift sign
  if(last60s!=null&&Math.abs(last60s)>=10){
    return last60s*(trade.dir==='UP'?1:-1)<0?'LATE_REVERSAL':'EARLY_PEAK';
  }
  return'WRONG_FROM_START'; // default — couldn't classify cleanly
};
const LOSS_PATTERN_LABELS={
  WRONG_FROM_START:{label:'Wrong from start',color:'rgba(244,114,182,0.95)',icon:'✗',hint:'Signal read was off entry. Tighten entry filter.'},
  EARLY_PEAK:     {label:'Early peak fade',  color:'rgba(229,200,112,0.85)',icon:'⤴',hint:'Peaked in first third then faded. Consider quicker take-profit.'},
  MID_REVERSAL:   {label:'Mid-window reversal',color:'rgba(229,200,112,0.85)',icon:'⤵',hint:'Was winning at midpoint. Watch for vol shifts.'},
  LATE_REVERSAL:  {label:'Late reversal',    color:'rgba(244,114,182,0.85)',icon:'⚡',hint:'Winning until last minute. Tighter trailing stop in final 90s.'},
  WHALE_SPIKE:    {label:'Whale spike',      color:'rgba(168,85,247,0.85)',icon:'🐋',hint:'Large contrary print near close. Not your read — circumstance.'},
  MACRO_SHOCK:    {label:'Macro shock',      color:'rgba(168,85,247,0.85)',icon:'⚠',hint:'External event spike during window. Not your read — circumstance.'},
};
// Patterns where signals were correct but external shock caused the loss.
//   Used by applyTradeLearning to skip/dampen gradient descent — don't punish
//   correct signals because the world moved unpredictably.
const SHOCK_LOSS_PATTERNS=new Set(['WHALE_SPIKE','MACRO_SHOCK']);

// V134: HPotter Future Grand Trend — multi-timeframe forecast
// Translated from PineScript v5 (Apr 2022 by HPotter)
// 
// Algorithm:
//   t[i] = 0.9 * t[i-length] + 0.1 * src[i] + (0.9*t[i-length] - 0.9*t[i-length*2])
//   fcast = t[current] + (t[current] - t[current-forecast])  (linear extrapolation)
//
// Returns: { forecastDir: 'UP'|'DOWN'|'NEUTRAL', forecastBps: signed bps, valid: bool }
// Returns valid=false if insufficient history
// V6.2.0: FUTURE TREND CHANNEL (ChartPrime port). Pure JS implementation of the user's
//   TradingView Pine script. Identifies trend regime via close crossing ATR-band around
//   SMA(100), and projects channel midline forward 50 bars. Inputs: candles newest-first,
//   length=100 SMA period, multi=3 channel-band ATR multiplier, extend=50 forward bars.
//   Returns: { trendDir, channelHigh, channelLow, channelPos (0-1), futurePriceBps, slopeBpsPerBar, valid }
const computeFutureTrendChannel=(candles,length=100,multi=3,extend=50)=>{
  if(!candles||candles.length<60)return{trendDir:'NEUTRAL',channelPos:0.5,futurePriceBps:0,slopeBpsPerBar:0,valid:false,reason:'insufficient'};
  const bars=candles.slice().reverse(); // oldest first
  const n=bars.length;
  // Adapt length to available data
  const L=Math.min(length,Math.floor(n*0.7));
  if(L<20)return{trendDir:'NEUTRAL',channelPos:0.5,futurePriceBps:0,slopeBpsPerBar:0,valid:false,reason:'too-short'};
  // Compute true range and ATR(200) — but cap at available history
  const atrLen=Math.min(200,Math.max(20,Math.floor(n*0.6)));
  const tr=new Array(n);
  for(let i=0;i<n;i++){
    if(i===0){tr[i]=bars[i].h-bars[i].l;continue;}
    const prev=bars[i-1];
    tr[i]=Math.max(bars[i].h-bars[i].l,Math.abs(bars[i].h-prev.c),Math.abs(bars[i].l-prev.c));
  }
  // ATR via SMA of true range (Pine's ta.atr is RMA but SMA close enough for our needs)
  const atrArr=new Array(n);
  let trSum=0;
  for(let i=0;i<n;i++){
    trSum+=tr[i];
    if(i>=atrLen)trSum-=tr[i-atrLen];
    atrArr[i]=i>=atrLen-1?trSum/atrLen:trSum/(i+1);
  }
  // ATR signal = ta.highest(atr, 100) — rolling max of ATR over 100 bars
  const highestLen=Math.min(100,Math.floor(n*0.5));
  const atrSig=new Array(n);
  for(let i=0;i<n;i++){
    let m=atrArr[i];
    for(let j=Math.max(0,i-highestLen+1);j<i;j++)if(atrArr[j]>m)m=atrArr[j];
    atrSig[i]=m;
  }
  // SMA(close, length)
  const smaArr=new Array(n);
  let smaSum=0;
  for(let i=0;i<n;i++){
    smaSum+=bars[i].c;
    if(i>=L)smaSum-=bars[i-L].c;
    smaArr[i]=i>=L-1?smaSum/L:smaSum/(i+1);
  }
  // Walk through bars tracking trend state
  let trend=null,lastFlipIdx=0,lastFlipMid=null;
  for(let i=1;i<n;i++){
    const upper=smaArr[i]+atrSig[i];
    const lower=smaArr[i]-atrSig[i];
    const upperPrev=smaArr[i-1]+atrSig[i-1];
    const lowerPrev=smaArr[i-1]-atrSig[i-1];
    const crossUp=bars[i].c>upper&&bars[i-1].c<=upperPrev;
    const crossDn=bars[i].c<lower&&bars[i-1].c>=lowerPrev;
    if(crossUp){trend=true;lastFlipIdx=i;lastFlipMid=(bars[i].h+bars[i].l)/2;}
    if(crossDn){trend=false;lastFlipIdx=i;lastFlipMid=(bars[i].h+bars[i].l)/2;}
  }
  if(trend===null)return{trendDir:'NEUTRAL',channelPos:0.5,futurePriceBps:0,slopeBpsPerBar:0,valid:false,reason:'no-flip-yet'};
  const trendDir=trend?'UP':'DOWN';
  // Current channel bands (using hl2 ± atr*multi like Pine's visual band)
  const lastBar=bars[n-1];
  const lastHl2=(lastBar.h+lastBar.l)/2;
  const lastAtr=atrSig[n-1];
  const channelHigh=lastHl2+lastAtr*multi;
  const channelLow=lastHl2-lastAtr*multi;
  const channelPos=Math.max(0,Math.min(1,(lastBar.c-channelLow)/(channelHigh-channelLow||1)));
  // Future projection — slope from flip point to current SMA20-of-mid
  const sma20Window=Math.min(20,n-lastFlipIdx);
  let mid20Sum=0;
  for(let j=Math.max(0,n-sma20Window);j<n;j++){
    mid20Sum+=(bars[j].h+bars[j].l)/2;
  }
  const currentMid=mid20Sum/sma20Window;
  const flipMid=lastFlipMid||currentMid;
  const barsSinceFlip=Math.max(1,n-1-lastFlipIdx);
  const slopePerBar=(currentMid-flipMid)/barsSinceFlip;
  const futurePrice=currentMid+slopePerBar*extend;
  const currentClose=lastBar.c;
  const futurePriceBps=((futurePrice-currentClose)/currentClose)*10000;
  const slopeBpsPerBar=(slopePerBar/currentClose)*10000;
  return{trendDir,channelHigh:Math.round(channelHigh),channelLow:Math.round(channelLow),channelPos:Math.round(channelPos*100)/100,futurePriceBps:Math.round(futurePriceBps*10)/10,slopeBpsPerBar:Math.round(slopeBpsPerBar*100)/100,barsSinceFlip,valid:true};
};

// V6.2.0: FUTURE GRAND TREND (HPotter port). Recursive low-pass-style transform looking
//   at bars 70 and 140 ago. Captures multi-hour structural direction.
//   t[i] = 0.9*t[i-70] + 0.1*close[i] + (0.9*t[i-70] - 0.9*t[i-140])
//        = 1.8*t[i-70] - 0.9*t[i-140] + 0.1*close[i]
//   fcast[i] = t[i] + (t[i] - t[i-100]) = 2*t[i] - t[i-100]
//   Direction: slope of fcast over recent bars (positive = UP, negative = DOWN).
const computeFutureGrandTrend=(candles,length=70,forecast=100)=>{
  if(!candles||candles.length<60)return{dir:'NEUTRAL',strengthBps:0,projectionBps:0,valid:false,reason:'insufficient'};
  const bars=candles.slice().reverse();
  const n=bars.length;
  const L=Math.min(length,Math.floor(n/3));
  const F=Math.min(forecast,Math.floor(n/2));
  if(L<10||F<10)return{dir:'NEUTRAL',strengthBps:0,projectionBps:0,valid:false,reason:'too-short'};
  // Build recursive t series
  const t=new Array(n);
  for(let i=0;i<n;i++){
    const src=bars[i].c;
    if(i<L*2){t[i]=src;continue;}
    const tLag=t[i-L];
    const tLag2=t[i-L*2];
    t[i]=1.8*tLag-0.9*tLag2+0.1*src;
  }
  // fcast at last bar
  const tLast=t[n-1];
  const tBack=t[Math.max(0,n-1-F)];
  const fcast=2*tLast-tBack;
  const currentPrice=bars[n-1].c;
  // Slope over last 20 bars of fcast for direction
  const slopeWindow=Math.min(20,Math.floor(n/4));
  const fcastBack=t[Math.max(0,n-1-slopeWindow)]; // approx — fcast[N-window] would need full fcast array, t is fine proxy
  const slope=(tLast-fcastBack)/slopeWindow;
  const slopeBps=(slope/currentPrice)*10000;
  const projectionBps=((fcast-currentPrice)/currentPrice)*10000;
  let dir='NEUTRAL';
  // Direction by projection magnitude — significant projection = directional
  if(projectionBps>15&&slopeBps>0)dir='UP';
  else if(projectionBps<-15&&slopeBps<0)dir='DOWN';
  // Strength = absolute projection in bps, capped to 0-100 scale (100bps = full strength)
  const strengthBps=Math.min(100,Math.abs(projectionBps));
  return{dir,strengthBps:Math.round(strengthBps),projectionBps:Math.round(projectionBps*10)/10,slopeBpsPerBar:Math.round(slopeBps*100)/100,valid:true};
};

const computeFGT=(candles,length=70,forecast=100)=>{
  // Need at least length*2 + forecast bars for a meaningful computation
  // Plus current bar. Be lenient: scale length down if needed.
  if(!candles||candles.length<20)return{forecastDir:'NEUTRAL',forecastBps:0,valid:false,reason:'insufficient'};
  // Adapt parameters to available data
  // PineScript: oldest is highest index, newest is index 0 in our convention (Tara's liveHistory[0] is newest)
  // We'll work with reversed array: oldest first
  const bars=candles.slice().reverse(); // bars[0] = oldest, bars[N-1] = newest
  const n=bars.length;
  // Auto-scale length and forecast to available history
  const _length=Math.min(length,Math.floor(n/3));
  const _forecast=Math.min(forecast,Math.floor(n/2));
  if(_length<5||_forecast<5)return{forecastDir:'NEUTRAL',forecastBps:0,valid:false,reason:'too-short'};
  // Build t series
  const t=new Array(n);
  for(let i=0;i<n;i++){
    const src=bars[i].c;
    if(i<_length){
      t[i]=src; // initialize with src (PineScript nz fallback)
      continue;
    }
    const tLag=t[i-_length];
    // Compute change in (0.9 * t[i-length]) over `length` bars
    let changeTerm=0;
    if(i>=_length*2){
      const tLag2=t[i-_length*2];
      changeTerm=0.9*tLag-0.9*tLag2;
    }
    t[i]=0.9*tLag+0.1*src+changeTerm;
  }
  // Forecast = t[last] + (t[last] - t[last - forecast])
  const tLast=t[n-1];
  const tBack=t[Math.max(0,n-1-_forecast)];
  const fcast=tLast+(tLast-tBack); // linear extrapolation forward
  const currentPrice=bars[n-1].c;
  const forecastBps=((fcast-currentPrice)/currentPrice)*10000;
  let forecastDir='NEUTRAL';
  if(forecastBps>10)forecastDir='UP';
  else if(forecastBps<-10)forecastDir='DOWN';
  return{forecastDir,forecastBps:Math.round(forecastBps),fcast:Math.round(fcast),valid:true,length:_length,forecast:_forecast};
};

// V134: Aggregate finer-grained candles into a coarser timeframe
// e.g. aggregate 5m candles into 15m by combining 3 at a time
const aggregateCandles=(candles,factor)=>{
  if(!candles||factor<=1)return candles;
  // candles[0] = newest. Group from newest: every `factor` consecutive bars become one aggregated bar
  const out=[];
  for(let i=0;i+factor<=candles.length;i+=factor){
    const group=candles.slice(i,i+factor);
    const o=group[group.length-1].o; // first bar of period (oldest)
    const c=group[0].c; // last bar of period (newest)
    const h=Math.max(...group.map(b=>b.h));
    const l=Math.min(...group.map(b=>b.l));
    const v=group.reduce((s,b)=>s+(b.v||0),0);
    out.push({time:group[0].time,o,h,l,c,v});
  }
  return out;
};

// V134: Volume Profile — find where most trading happened recently
// VPOC (Volume Point of Control) acts as support/resistance.
// If we're locked UP and a strong VPOC sits between price and strike → it's resistance.
const computeVolumeProfile=(history)=>{
  if(!history||history.length<10)return{vpoc:0,vah:0,val:0,strength:0};
  const recent=history.slice(0,40); // last 40 candles
  // Bin price levels into $50 buckets
  const buckets={};
  recent.forEach(c=>{
    const lo=Math.floor((c.l||c.c)/50)*50;
    const hi=Math.floor((c.h||c.c)/50)*50;
    const v=c.v||0;
    // Distribute volume across the candle's price range
    const numBuckets=Math.max(1,Math.round((hi-lo)/50)+1);
    for(let p=lo;p<=hi;p+=50){
      buckets[p]=(buckets[p]||0)+(v/numBuckets);
    }
  });
  // Find max-volume bucket = VPOC
  const sorted=Object.entries(buckets).sort((a,b)=>b[1]-a[1]);
  if(sorted.length===0)return{vpoc:0,vah:0,val:0,strength:0};
  const vpoc=parseFloat(sorted[0][0])+25; // mid-bucket
  const totalVol=Object.values(buckets).reduce((s,v)=>s+v,0);
  const vpocVol=sorted[0][1];
  const strength=totalVol>0?vpocVol/totalVol:0;
  // Value Area: 70% of volume around VPOC
  let cumVol=vpocVol;
  let vah=vpoc,val=vpoc;
  const target=totalVol*0.70;
  while(cumVol<target&&(vah<sorted[0][0]+1000||val>sorted[0][0]-1000)){
    const upBucket=parseFloat(sorted[0][0])+(vah-vpoc+50);
    const dnBucket=parseFloat(sorted[0][0])-(vpoc-val+50);
    const upVol=buckets[upBucket]||0;
    const dnVol=buckets[dnBucket]||0;
    if(upVol>=dnVol){vah=upBucket+25;cumVol+=upVol;}
    else{val=dnBucket+25;cumVol+=dnVol;}
    if(cumVol>=target)break;
  }
  return{vpoc,vah,val,strength};
};

// V134: useDepthFlash — high-frequency order book polling at 2.5s
// Bloomberg's 8s interval misses fast wall changes during volatility.
// This hook only fetches the depth endpoint, which is the time-critical one.
// V134: Fetch candles at 1m, 3m, 5m, 15m for HPotter FGT analysis
// Returns { c1m: [...], c3m: [...], c5m: [...], c15m: [...] }
const useMultiTFCandles=(asset)=>{
  const[tfCandles,setTfCandles]=useState({c1m:[],c3m:[],c5m:[],c15m:[]});
  useEffect(()=>{
    if(typeof window==='undefined')return;
    let mounted=true;
    const _cfg=ASSET_CONFIG[asset]||ASSET_CONFIG.BTC;
    const _cbSym=_cfg.cb||'BTC-USD';
    const _bnSym=_cfg.binance||'BTCUSDT';
    const fetchInterval=async(label,gran)=>{
      try{
        // Coinbase first (more permissive CORS)
        const r=await fetch(`https://api.exchange.coinbase.com/products/${_cbSym}/candles?granularity=${gran}`,{cache:'no-store'});
        if(!r.ok)throw new Error('CB '+r.status);
        const d=await r.json();
        if(!Array.isArray(d))throw new Error('bad shape');
        return d.slice(0,300).map(c=>({time:c[0],l:parseFloat(c[1]),h:parseFloat(c[2]),o:parseFloat(c[3]),c:parseFloat(c[4]),v:parseFloat(c[5])}));
      }catch(e){
        // Fallback Binance
        try{
          const ivMap={60:'1m',180:'3m',300:'5m',900:'15m'};
          const iv=ivMap[gran]||'1m';
          const r2=await fetch(`https://api.binance.com/api/v3/uiKlines?symbol=${_bnSym}&interval=${iv}&limit=300`);
          const d2=await r2.json();
          if(!Array.isArray(d2))throw new Error('binance bad');
          return d2.map(d=>({time:d[0]/1000,o:parseFloat(d[1]),h:parseFloat(d[2]),l:parseFloat(d[3]),c:parseFloat(d[4]),v:parseFloat(d[5])})).reverse();
        }catch(e2){return[];}
      }
    };
    const fetchAll=async()=>{
      const[c1m,c3m,c5m,c15m]=await Promise.all([
        fetchInterval('1m',60),
        fetchInterval('3m',180),
        fetchInterval('5m',300),
        fetchInterval('15m',900),
      ]);
      if(mounted)setTfCandles({c1m,c3m,c5m,c15m});
    };
    fetchAll();
    const iv=setInterval(fetchAll,30000);
    return()=>{mounted=false;clearInterval(iv);};
  },[asset]);
  return tfCandles;
};

const useDepthFlash=()=>{
  const[depth,setDepth]=useState({obImbalanceLive:0,liqLongWallLive:0,liqShortWallLive:0,liqLongUSDLive:0,liqShortUSDLive:0,depthUpdateAge:0,depthLastUpdate:0});
  useEffect(()=>{
    if(typeof window==='undefined')return;
    let mp=0;
    const f=async()=>{
      try{
        // Get mark price quickly first
        const pR=await fetch('https://fapi.binance.com/fapi/v1/premiumIndex?symbol=BTCUSDT');
        const p=await pR.json();
        mp=parseFloat(p.markPrice)||mp;
        if(!mp)return;
        // Then depth
        const dR=await fetch('https://fapi.binance.com/fapi/v1/depth?symbol=BTCUSDT&limit=50');
        const d=await dR.json();
        if(!d?.bids||!d?.asks)return;
        let mBW=0,mBP=0,tBL=0,mAW=0,mAP=0,tAL=0;
        d.bids.forEach(([p,q])=>{const pr=parseFloat(p),qt=parseFloat(q),dist=((mp-pr)/mp)*100;if(dist<2&&dist>0){const usd=pr*qt;tBL+=usd;if(usd>mBW){mBW=usd;mBP=pr;}}});
        d.asks.forEach(([p,q])=>{const pr=parseFloat(p),qt=parseFloat(q),dist=((pr-mp)/mp)*100;if(dist<2&&dist>0){const usd=pr*qt;tAL+=usd;if(usd>mAW){mAW=usd;mAP=pr;}}});
        const obImbal=tBL+tAL>0?(tBL-tAL)/(tBL+tAL):0; // -1=asks heavy, +1=bids heavy
        setDepth({obImbalanceLive:obImbal,liqLongWallLive:mAP,liqShortWallLive:mBP,liqLongUSDLive:tAL,liqShortUSDLive:tBL,depthUpdateAge:0,depthLastUpdate:Date.now()});
      }catch(e){/* silent fail */}
    };
    f();
    const iv=setInterval(f,2500); // 2.5s polling
    return()=>clearInterval(iv);
  },[]);
  return depth;
};

const useBloomberg=()=>{const[data,setData]=useState({fundingRate:0,fundingRatePrev:0,nextFundingTime:0,openInterest:0,openInterestUSD:0,oiChange5m:0,basisBps:0,markPrice:0,indexPrice:0,longShortRatio:1,topTraderLSPositions:1,binanceFuturesVol24h:0,liqLongWall:0,liqShortWall:0,liqLongUSD:0,liqShortUSD:0,longWallAgeMs:0,shortWallAgeMs:0,lastUpdate:0,status:'connecting'});const oiSnaps=useRef([]);const wallHistRef=useRef([]);useEffect(()=>{if(typeof window==='undefined')return;const f=async()=>{try{const R=await Promise.allSettled([fetch('https://fapi.binance.com/fapi/v1/premiumIndex?symbol=BTCUSDT').then(r=>r.json()),fetch('https://fapi.binance.com/fapi/v1/openInterest?symbol=BTCUSDT').then(r=>r.json()),fetch('https://fapi.binance.com/fapi/v1/fundingRate?symbol=BTCUSDT&limit=3').then(r=>r.json()),fetch('https://fapi.binance.com/futures/data/globalLongShortAccountRatio?symbol=BTCUSDT&period=5m&limit=1').then(r=>r.json()),fetch('https://fapi.binance.com/futures/data/topLongShortPositionRatio?symbol=BTCUSDT&period=5m&limit=1').then(r=>r.json()),fetch('https://fapi.binance.com/fapi/v1/ticker/24hr?symbol=BTCUSDT').then(r=>r.json()),fetch('https://fapi.binance.com/fapi/v1/depth?symbol=BTCUSDT&limit=50').then(r=>r.json())]);const[pR,oR,fR,gR,tR,t24R,dR]=R;const now=Date.now();let u={lastUpdate:now,status:'live'};if(pR.status==='fulfilled'&&pR.value){const p=pR.value;const mk=parseFloat(p.markPrice)||0,ix=parseFloat(p.indexPrice)||0;u.fundingRate=parseFloat(p.lastFundingRate)||0;u.markPrice=mk;u.indexPrice=ix;u.basisBps=ix>0?((mk-ix)/ix)*10000:0;u.nextFundingTime=parseInt(p.nextFundingTime)||0;}if(oR.status==='fulfilled'&&oR.value){const oi=parseFloat(oR.value.openInterest)||0;oiSnaps.current.push({oi,time:now});oiSnaps.current=oiSnaps.current.filter(s=>now-s.time<600000);const o5=oiSnaps.current.find(s=>now-s.time>=270000&&now-s.time<=330000);u.openInterest=oi;u.openInterestUSD=oi*(u.markPrice||0);u.oiChange5m=o5?((oi-o5.oi)/o5.oi)*100:0;}if(fR.status==='fulfilled'&&Array.isArray(fR.value)&&fR.value.length>=2)u.fundingRatePrev=parseFloat(fR.value[1]?.fundingRate)||0;if(gR.status==='fulfilled'&&Array.isArray(gR.value)&&gR.value[0])u.longShortRatio=parseFloat(gR.value[0].longShortRatio)||1;if(tR.status==='fulfilled'&&Array.isArray(tR.value)&&tR.value[0])u.topTraderLSPositions=parseFloat(tR.value[0].longShortRatio)||1;if(t24R.status==='fulfilled'&&t24R.value)u.binanceFuturesVol24h=parseFloat(t24R.value.quoteVolume)||0;if(dR.status==='fulfilled'&&dR.value?.bids&&dR.value?.asks){const mp=u.markPrice||0;if(mp>0){let mBW=0,mBP=0,tBL=0,mAW=0,mAP=0,tAL=0;dR.value.bids.forEach(([p,q])=>{const pr=parseFloat(p),qt=parseFloat(q),dist=((mp-pr)/mp)*100;if(dist<2&&dist>0){const usd=pr*qt;tBL+=usd;if(usd>mBW){mBW=usd;mBP=pr;}}});dR.value.asks.forEach(([p,q])=>{const pr=parseFloat(p),qt=parseFloat(q),dist=((pr-mp)/mp)*100;if(dist<2&&dist>0){const usd=pr*qt;tAL+=usd;if(usd>mAW){mAW=usd;mAP=pr;}}});u.liqLongWall=mAP;u.liqShortWall=mBP;u.liqLongUSD=tAL;u.liqShortUSD=tBL;
const wH=wallHistRef.current;wH.push({t:now,longWall:mAP,shortWall:mBP});while(wH.length>0&&now-wH[0].t>60000)wH.shift();
let lwAge=0;if(mAP>0){let oldest=now;for(const s of wH){if(s.longWall>0&&Math.abs((s.longWall-mAP)/mAP*10000)<10)oldest=Math.min(oldest,s.t);}lwAge=now-oldest;}
let swAge=0;if(mBP>0){let oldest=now;for(const s of wH){if(s.shortWall>0&&Math.abs((s.shortWall-mBP)/mBP*10000)<10)oldest=Math.min(oldest,s.t);}swAge=now-oldest;}
u.longWallAgeMs=lwAge;u.shortWallAgeMs=swAge;}}setData(prev=>({...prev,...u}));}catch(e){setData(prev=>({...prev,status:'error'}));}};f();const iv=setInterval(f,8000);return()=>clearInterval(iv);},[]);return data;};

// ═══════════════════════════════════════
// SYNTHETIC DATA FALLBACK (always shows a chart)
// ═══════════════════════════════════════
const generateSyntheticBTC=(basePrice=84000,candles=120,intervalSec=60)=>{
  const out=[];let p=basePrice;const now=Math.floor(Date.now()/1000);
  // seeded random for consistency
  let seed=now%99999;const rng=()=>{seed=(seed*9301+49297)%233280;return seed/233280;};
  for(let i=candles-1;i>=0;i--){
    const vol=p*0.0009;
    const trend=(rng()-0.48)*vol;
    const range=rng()*vol*2.5;
    const o=p;const c=p+trend;
    const h=Math.max(o,c)+rng()*range;
    const l=Math.min(o,c)-rng()*range;
    const v=5+rng()*40;
    out.push({time:now-(i*intervalSec),o,h,l,c,v});
    p=c;
  }
  return out;
};

