        // V6.5.3: Also auto-resolve misclassified SITOUT entries on incoming cloud data —
        //   if entry has dir='UP'/'DOWN' + valid strike + valid close, compute the real WIN/LOSS.
        const _isCorrupt=(e)=>{
          if(!e||(e.result!=='WIN'&&e.result!=='LOSS'))return false;
          if(e.strike&&e.closingPrice&&Math.abs(e.closingPrice-e.strike)/e.strike>0.20)return true;
          if(e.outcomeDir&&(e.dir==='UP'||e.dir==='DOWN')){
            const _shouldBeWin=e.dir===e.outcomeDir;
            if(_shouldBeWin&&e.result==='LOSS')return true;
            if(!_shouldBeWin&&e.result==='WIN')return true;
          }
          return false;
        };
        // V7.0.5: Detect & fix misclassified asset tags. The V7.0.3 stale-closure bug
        //   caused some entries (esp. SOL trades) to be tagged as ETH. Strike magnitude
