          const lW=Number(prev?.[k]?.wins)||0,lL=Number(prev?.[k]?.losses)||0;
          const cW=Number(d?.[k]?.wins)||0,cL=Number(d?.[k]?.losses)||0;
          const merged={wins:Math.max(lW,cW),losses:Math.max(lL,cL)};
