    const tapeSuperOpposes=_upSuperOpposes||_downSuperOpposes;
    // V5.6.4: KALSHI CROSS-CHECK — market price is a third opinion. Use as sanity check:
    //   - If Kalshi clearly agrees with our direction → boost confidence, allow faster lock
    //   - If Kalshi clearly disagrees → require materially higher conviction or sit out
    //   kalshiYesPrice is 0-100, representing market's P(price closes above strike) = P(UP).
    const _kPct=kalshiYesPrice;
    const kalshiAvail=_kPct!=null&&_kPct>0&&_kPct<100;
    const kalshiAgrees=kalshiAvail&&((dir==='UP'&&_kPct>=55)||(dir==='DOWN'&&_kPct<=45));
    const kalshiStronglyAgrees=kalshiAvail&&((dir==='UP'&&_kPct>=65)||(dir==='DOWN'&&_kPct<=35));
    // Disagreement: market sees the opposite direction with material conviction
    const kalshiDisagrees=kalshiAvail&&((dir==='UP'&&_kPct<=40)||(dir==='DOWN'&&_kPct>=60));
    const kalshiStronglyDisagrees=kalshiAvail&&((dir==='UP'&&_kPct<=30)||(dir==='DOWN'&&_kPct>=70));
    // V5.7.7: Kalshi extreme certainty threshold — when market is ≥90% one way and we're
    //   calling opposite, the disagreement is severe enough that we need extraordinary
    //   evidence to override (BOTH tape alignment AND pattern alignment).
    const kalshiExtremeDisagrees=kalshiAvail&&((dir==='UP'&&_kPct<=10)||(dir==='DOWN'&&_kPct>=90));
    // V5.7.7: STRIKE-FAVORABLE — is current price already on the right side of the strike?
    //   For UP candidate: price > strike means we're already where we want to settle.
    //   For DOWN candidate: price < strike likewise. This is a "material evidence" signal.
    const _gapBpsForDir=analysis?.realGapBps||0;
    const strikeFavorable=(dir==='UP'&&_gapBpsForDir>0)||(dir==='DOWN'&&_gapBpsForDir<0);
    // V5.7.7: CONFLUENCE detection — all four primary signals point the same way.
    //   When this fires, we have orthogonal confirmation and can fast-lock in 5-8 samples
    //   regardless of the slow-tier criteria. Last round's clean DOWN: tape, FGT, score
    //   sign, strike all DOWN → confluent. The win round vs the failure round is exactly
    //   this distinction. Note this evaluates per-direction (UP confluence has all-UP
    //   conditions, DOWN confluence has all-DOWN).
    const _scoreSignAgrees=(dir==='UP'&&conviction>=10)||(dir==='DOWN'&&conviction>=10); // post>= +10pt for UP, <=-10pt for DOWN
    const _fgtSignAgrees=(dir==='UP'&&(analysis?.mtfAlignment||0)>=0.7)||(dir==='DOWN'&&(analysis?.mtfAlignment||0)<=-0.7);
    const isConfluent=tapeStronglyAgrees&&_fgtSignAgrees&&_scoreSignAgrees&&strikeFavorable;
    const isSuperConfluent=tapeSuperStrong&&_fgtSignAgrees&&_scoreSignAgrees&&strikeFavorable&&!kalshiDisagrees;
    // V6.0.1: RISING-CONFLUENCE — early-entry tier. By the time isConfluent fires, the
    //   move has often already happened — Kalshi reads 80-90% and the entry is too late.
    //   This catches setups while they're BUILDING. Looser thresholds on each signal but
    //   still requires multiple to lean: 15s tape leading, FGT pointing right way (≥0.4
    //   not 0.7), conviction ≥8 (not 10), price still actionable. Locks in 3 samples.
    const _15sLeads=(dir==='UP'&&_tape15>=60)||(dir==='DOWN'&&_tape15<=40);
    const _fgtLeansDir=(dir==='UP'&&(analysis?.mtfAlignment||0)>=0.4)||(dir==='DOWN'&&(analysis?.mtfAlignment||0)<=-0.4);
    const _convLean=conviction>=8;
    // V6.0.7: TAPE-LED FAST-LOCK. The user's screenshot: tape was 90% one-sided across
    //   ALL windows but Tara was sitting at WATCHING because q=11 fell below the 30 floor.
    //   That's wrong — when tape is overwhelming (≥70% in ≥2 of 3 windows), it IS the
    //   signal. Quality score is a derived aggregate that lags actual order flow; waiting
    //   for it when raw tape data is unanimous defeats the purpose of having a real-time
    //   bot. Tape-led bypasses q-floor and conv-floor, locks in 5 samples (~5s).
    //   V6.1.2: TIGHTENED. Real-world test caught the failure mode: window opens, price
    //   ticks UP slightly for ~1 minute, tape briefly registers buy, Tara locks UP — but
    //   the bigger trajectory was DOWN and price reverses. Now tape-led requires ALSO
    //   either FGT-direction-aligned (multi-timeframe pattern agrees) OR strike already
    //   strongly favorable (price already on the right side by ≥8bps). Either confirmation
    //   shows the bigger picture isn't fighting the tape signal. Plus: tape-led blocked
    //   entirely in RANGE-CHOP regime — chop is where most "swing" windows live and tape
    //   is unreliable in chop.
    const _strikeReasonable=strikeFavorable||Math.abs(_gapBpsForDir)<=30;
    const _strikeStronglyFavorable=strikeFavorable&&Math.abs(_gapBpsForDir)>=8;
    const _fgtAlignsDir=_fgtSignAgrees&&fgtAbs>=0.7;
    const _isChopRegime=['RANGE-CHOP','CHOPPY','RANGE-BOUND'].includes(analysis.regime);
    // V7.2: TAPE-EXTREME GUARD. When 15s tape is at flush extremes (≥95% one direction)
    //   the move is more likely capitulation/exhaustion than continuation. Reversal odds
    //   spike. Block tape-led tier in this state — wait for tape to step back from the
    //   wall. Real-world example: 10:15-10:30 trade where 15s tape was 99.5% SELL, Tara
    //   tape-led DOWN at 99% conf, price reversed +6.8 bps and trade lost. Guard catches
    //   this exact pattern.
    const _tapeAtFlushExtreme=(dir==='UP'&&_tape15>=95)||(dir==='DOWN'&&_tape15<=5);
    // V7.2: GAP-NOT-MARGINAL. TAPE-LED was originally permissive on gap because tape itself
    //   was the signal. But marginal gap (price 0-2 bps from strike) means the binary outcome
    //   is genuinely uncertain — even strong tape can't compensate. Require gap ≥3 bps in
    //   direction at minimum for tape-led. Combined with the extreme guard above, this kills
    //   the "strong tape at near-strike inflection point" failure pattern.
    const _gapNotMarginal=strikeFavorable&&Math.abs(_gapBpsForDir)>=3;
    const isTapeLed=tapeSuperStrong&&conviction>=4&&!tapeOpposes&&!kalshiExtremeDisagrees&&_strikeReasonable
      &&(_fgtAlignsDir||_strikeStronglyFavorable)
      &&!_isChopRegime
      &&!_tapeAtFlushExtreme   // V7.2: extreme tape = exhaustion, not continuation
      &&_gapNotMarginal;       // V7.2: gap must be ≥3 bps in direction
    // V6.2.0: STRUCTURAL-LED TIER — primary fast-lock based on grand trend + trend channel.
    //   These are the user's preferred indicators: multi-hour structural context, looking
    //   at where price IS GOING, not where order flow already showed up.
    // V6.2.1: REWRITTEN to match user's actual workflow. He switches between 1m/5m/15m on
    //   TradingView and only takes a call when indicators agree across timeframes. So
    //   structural-led now requires ≥4 of 6 readings (Trend Channel × 3 TFs + Grand Trend
    //   × 3 TFs) to point the lock direction. Single-timeframe agreement isn't enough.
    const _gt=analysis?.grandTrend;
    const _tc=analysis?.trendChannel;
    const _struct=analysis?.structAlignment;
    // Cross-TF cross-indicator alignment in the lock direction
    const _structAgreesDir=_struct?.dir===dir&&_struct?.count>=4; // 4 of 6 signals minimum
    // Channel position alignment (5m): for UP locks, want price in lower half (room to run up).
    //   For DOWN locks, want price in upper half. Mid-channel = no edge.
    const _tcPosFavors=_tc?.valid&&((dir==='UP'&&_tc.channelPos<=0.45)||(dir==='DOWN'&&_tc.channelPos>=0.55));
    // Grand trend strength on 5m needs to be meaningful too (not just neutral with tied counts)
    const _gtStrengthOk=_gt?.valid&&_gt.strengthBps>=20;
    // Strong version: 5+ of 6 align AND strength is real (the "perfect alignment" you'd see
    //   on TradingView when all timeframes scream the same direction)
    const _structStrong=_struct?.dir===dir&&_struct?.count>=5&&_gtStrengthOk;
    // Standard structural-led: 4 of 6 align + favorable channel position + meaningful strength
    const isStructuralLed=(_structStrong||(_structAgreesDir&&(_tcPosFavors||_gtStrengthOk)))
      &&conviction>=6
      &&!tapeSuperOpposes
      &&_strikeReasonable
      &&!kalshiExtremeDisagrees;
    const _strikeActionable=strikeFavorable||Math.abs(_gapBpsForDir)<=20;
    // Rising-confluence requires 3 of {15s tape, FGT-leans, score-leans, strike-actionable}
    //   plus existing vetoes still apply. Don't fire if already isConfluent — we have a
    //   stronger signal then.
    const _risingScore=(_15sLeads?1:0)+(_fgtLeansDir?1:0)+(_convLean?1:0)+(_strikeActionable?1:0);
    // V6.0.2: TIGHTENED — require ALL 4 leading conditions (was 3/4) AND no Kalshi
    //   mild disagreement (was: only extreme blocked). User constraint: WR must not
    //   dip below 70%. The 3/4 threshold was too permissive for high-WR target.
    const isRisingConfluence=!isConfluent&&_risingScore>=4&&!tapeOpposes&&!kalshiDisagrees;
    const _dirLead=`${dir} lean (${conviction.toFixed(0)}pt)`;
    // V7.8: Removed the dial-tier-block SIT_OUT (was V7.4). User: "remove skips completely,
    //   we trade each round." Dial position now only affects sample-count multipliers and
    //   search-phase length — NOT whether to commit. Tier-blocked trades still happen,
    //   they just take more samples to confirm. The 90s hard cap (lifecycle effect) ensures
    //   we always exit with a directional call.
    // V7.4: SPEED DIAL TIER FILTER. The dial now determines the MINIMUM tier that can lock.
    //   Previously the dial only adjusted Q_FLOOR / CONV_FLOOR / sample-count multipliers —
    //   too subtle to feel. Now patient mode actively sits out lower-tier trades:
    //     dial >=80 (patient/strict): only super-confluence + structural-led (~20-30% of setups)
    //     dial 50-79 (balanced):       also allows confluence (skips tape-led + rising)
    //     dial 30-49 (mid-fast):       also allows tape-led + rising
    //     dial <30  (fast):            all tiers including single-signal (current behavior)
    //   Per-tier WR audit (V7.2) showed super and structural have meaningfully higher WR than
    //   tape-led — so patient mode trading those trades only should lift WR materially.
    // V7.8: Dial-tier block REMOVED. User said "remove skips completely". The dial now
    //   only affects sample-count multiplier and search-phase length. Tier checks still
    //   inform tier labeling for analytics (per-tier WR audit) but no longer block locks.
    //   Q-floor and conviction-floor checks below are similarly relaxed via the always-
    //   commit ladder in the lifecycle (Path A/B/C above).
    // Gate 1: quality floor
    // V6.0.7: tape-led bypass. When tape is super-strong agreeing, q-floor is irrelevant —
    //   raw order flow is direct evidence; quality score is a lagging aggregate.
    if(q<Q_FLOOR&&!isTapeLed){
      return{call:'SIT_OUT',reason:`Signal weak — quality ${q}/${Q_FLOOR}`,confidence:0,direction:dir,conviction,phase:'WATCHING'};
    }
    // Gate 2: conviction floor (THE coin-flip filter)
    // V6.0.7: tape-led bypass — tape ≥70% across windows is enough directional evidence
    //   even when posterior is still developing.
    if(conviction<CONV_FLOOR&&!isTapeLed){
      return{call:'SIT_OUT',reason:`Coin flip — only ${conviction.toFixed(0)}pt off neutral (need ${CONV_FLOOR})`,confidence:0,direction:dir,conviction,phase:'WATCHING'};
    }
    // V5.7.7 Gate 2.5: TAPE-OPPOSES veto. The most direct fix for FGT-alone failures.
    //   When two tape windows show ≥70% the OTHER way, no posterior can save this call —
    //   actual order flow is the truth. Even 60%+ opposition with no confluence is a hard veto.
    if(tapeSuperOpposes){
      return{call:'SIT_OUT',reason:`${_dirLead} — tape ${(dir==='UP'?(100-tapeBuyPct):tapeBuyPct).toFixed(0)}% opposite, fighting flow`,confidence:0,direction:dir,conviction,phase:'WATCHING'};
    }
    // V6.2.2: When Kalshi is ALREADY extreme (≥85% in our direction), it cannot rescue
    //   tape opposition. Real-world failure: tape was 78% sell, Tara locked UP because
    //   Kalshi at 90% "strongly agrees" — but Kalshi at 90% means zero edge (LATE ENTRY,
    //   -9pt). Correct behavior is sit out: the market has already priced in everything,
    //   we can't profitably fade tape just because we agree with the priced-in side.
    const _kalshiAlreadyExtreme=kalshiAvail&&((dir==='UP'&&_kPct>=85)||(dir==='DOWN'&&_kPct<=15));
    if(tapeOpposes&&!kalshiStronglyAgrees){
      return{call:'SIT_OUT',reason:`${_dirLead} — tape ${(dir==='UP'?(100-tapeBuyPct):tapeBuyPct).toFixed(0)}% opposite, no Kalshi rescue`,confidence:0,direction:dir,conviction,phase:'WATCHING'};
    }
    if(tapeOpposes&&_kalshiAlreadyExtreme){
      return{call:'SIT_OUT',reason:`${_dirLead} — tape opposes & Kalshi ${_kPct}% means no edge (late entry)`,confidence:0,direction:dir,conviction,phase:'WATCHING'};
    }
    // V6.4: ASYMMETRY EXHAUSTION GATE. When the latest swing strongly opposes our intended
    //   lock direction AND it's meaningfully stronger than the prior swing in our direction,
    //   that's structural exhaustion — the trend we want to ride is fading. Block the lock.
    //   "This down move is stronger than the up move was" → don't lock UP into a fading trend.
    const _asym=convictionAsymmetry;
    if(_asym?.valid&&_asym.score>=40&&_asym.latestDir&&_asym.latestDir!==dir){
      // Latest swing is opposite our lock direction and meaningfully strong (40+ asymmetry).
      //   This is the exhaustion case humans intuit. Sit out, wait for trend to actually resume.
      return{call:'SIT_OUT',reason:`${_dirLead} — exhaustion: ${_asym.latestDir} swing ${_asym.score}pt stronger than prior ${dir} swing`,confidence:0,direction:dir,conviction,phase:'WATCHING'};
    }
    // V6.4: REGIME TRANSITION GATE. If regime is in flux (multiple labels in last 60s),
    //   sit out — conditions are too unstable to commit. If transitioning-to-range and we're
    //   trying to ride a trend, that's the trend dying — sit out unless conviction is very high.
    const _regTrans=regimeTransitionRef.current;
    if(_regTrans?.state==='flux'){
      return{call:'SIT_OUT',reason:`${_dirLead} — regime in flux (${_regTrans.fromRegime}→${_regTrans.toRegime}), waiting`,confidence:0,direction:dir,conviction,phase:'WATCHING'};
    }
    if(_regTrans?.state==='transitioning-to-range'&&conviction<25){
      return{call:'SIT_OUT',reason:`${_dirLead} — trend dying (transitioning to range), conviction ${Math.round(conviction)}pt insufficient`,confidence:0,direction:dir,conviction,phase:'WATCHING'};
    }
    // V6.5: SHORT SQUEEZE TRAP GATE. Evidence-based fix from V6.4.0 export analysis.
    //   Data: structural-led × SHORT SQUEEZE = 4W/4L (50% WR). All 4 losses were UP calls
    //   with FGT 0.0/4. Tape-led × SHORT SQUEEZE = 1W/2L (33% WR), same pattern.
    //   SHORT SQUEEZE is a temporary spike from forced short-covering — it LOOKS like
    //   bullish momentum but typically exhausts within 1-2 windows. Without FGT confirming
    //   the underlying trend (≥1.5/4 same direction), the squeeze is fading, not continuing.
    //   Block UP locks in SHORT SQUEEZE unless FGT clearly confirms.
    const _isShortSqueeze=analysis.regime==='SHORT SQUEEZE';
    const _fgtMag=Math.abs(analysis.mtfAlignment||0);
    const _fgtAgreesDir=(analysis.mtfAlignment>0&&dir==='UP')||(analysis.mtfAlignment<0&&dir==='DOWN');
    if(_isShortSqueeze&&dir==='UP'&&(!_fgtAgreesDir||_fgtMag<1.5)&&(isStructuralLed||isTapeLed)){
      return{call:'SIT_OUT',reason:`${_dirLead} — SHORT SQUEEZE without FGT confirmation (FGT ${_fgtMag.toFixed(1)}/4) — squeeze likely exhausting`,confidence:0,direction:dir,conviction,phase:'WATCHING'};
    }
    // V5.7.7 Gate 2.6: Kalshi extreme-disagreement gate. When market is ≥90% certain the
    //   other way, we need BOTH tape alignment AND pattern alignment to commit. Otherwise sit.
    if(kalshiExtremeDisagrees&&!(tapeStronglyAgrees&&_fgtSignAgrees)){
      return{call:'SIT_OUT',reason:`${_dirLead} — Kalshi ${_kPct}% says opposite, no override`,confidence:0,direction:dir,conviction,phase:'WATCHING'};
    }
    // Gate 3: Kalshi material disagreement — market sees opposite direction strongly.
    //   V6.0.9: Tightened to conv ≥30 (was ≥25). User feedback: Tara fights Kalshi too often
    //   and loses on those bets. Keep the override threshold high so we only fade Kalshi
    //   when posterior is at 80%+ in our direction.
    if(kalshiStronglyDisagrees&&conviction<30){
      return{call:'SIT_OUT',reason:`${_dirLead} — Kalshi ${_kPct}% opposite, need stronger conviction`,confidence:0,direction:dir,conviction,phase:'WATCHING'};
    }
    // V6.0.9 Gate 3b: Mild Kalshi disagreement (≥60% opposite) now also needs some override
    //   conviction. Was unguarded before — Tara would call against Kalshi at 60% with just
    //   conv 10. That's the source of "wrong-position trades" the user described.
    if(kalshiDisagrees&&!kalshiStronglyDisagrees&&conviction<18&&!isTapeLed){
      return{call:'SIT_OUT',reason:`${_dirLead} — Kalshi ${_kPct}% disagrees, conviction insufficient to fade`,confidence:0,direction:dir,conviction,phase:'WATCHING'};
    }
    // Gate 4: FGT support — primary multi-timeframe signal must show some pulse
    const isFastTrackRegime=['TRENDING UP','TRENDING DOWN','SHORT SQUEEZE','LONG SQUEEZE'].includes(analysis.regime);
    const fgtMin=tapeStronglyAgrees||kalshiStronglyAgrees?0.5:1.0; // V5.6.4: was 0.0/0.4/0.7
    if(fgtAbs<fgtMin&&!isFastTrackRegime){
      return{call:'SIT_OUT',reason:`${_dirLead} — FGT ${fgtAbs.toFixed(1)}/4 mixed across timeframes`,confidence:0,direction:dir,conviction,phase:'WATCHING'};
    }
    // V6.0.9 Gate 4.5: LATE-COMMIT GUARD. When elapsed > 70% of window, only high-quality
    //   tiers (super-confluence, confluence, tape-led, exceptional, strong+) can commit.
    //   Below that, sit out — late single-signal locks were the source of "confirmed DOWN
    //   with 4 minutes left" timing complaints. Better to have NO call than a panic-late one.
    const _elapsedFrac=_elapsed/(_remaining+_elapsed||1);
    const _isLateWindow=_elapsedFrac>=0.70;
    const _isHighTier=isSuperConfluent||isConfluent||isTapeLed||isRisingConfluence||(q>=75&&conviction>=18);
    if(_isLateWindow&&!_isHighTier){
      return{call:'SIT_OUT',reason:`${_dirLead} — too late for single-signal (${Math.round(_elapsedFrac*100)}% elapsed)`,confidence:0,direction:dir,conviction,phase:'WATCHING'};
    }
    // V6.0.3: Gate 5 (added in 6.0.2 — high-WR quality threshold) REMOVED. The user
    //   correctly pointed out that "below default tier" is not the same as "coin flip."
    //   Existing gates already filter coin-flips (Q_FLOOR=30, CONV_FLOOR=10, tape opposes,
    //   tape super-strong opposes, Kalshi extreme, Kalshi strong-disagree+low-conv, FGT min).
    //   If a setup gets past these, it has directional information — Tara should call it,
    //   just slowly. The 2-3 min lock-time cap is enforced by capping needSamples, not
    //   by refusing the call. WR is protected by the confluence-bucket self-learning
    //   which adjusts confidence per-bucket based on observed WR.
    // SOFT gates — apply confidence haircuts instead of blocking
    let confidenceHaircut=0;
    let haircutReasons=[];
    if(winType==='DEAD'||winType==='WHIPSAW'){
      if(q<50&&!tapeStronglyAgrees&&!kalshiStronglyAgrees){
        return{call:'SIT_OUT',reason:`${_dirLead} — ${winType} regime + q${q} no consensus from tape/kalshi`,confidence:0,direction:dir,conviction,phase:'WATCHING'};
      }
      confidenceHaircut+=15;
      haircutReasons.push(`${winType} regime`);
    }
    const isDivergent=
      (dir==='UP'&&(vfLabel==='BUY-DIVERGENT'||vfLabel==='BUY-FAILING'))||
      (dir==='DOWN'&&(vfLabel==='SELL-DIVERGENT'||vfLabel==='SELL-FAILING'));
    if(isDivergent){
      if(q<50&&conviction<18&&!tapeStronglyAgrees){
        return{call:'SIT_OUT',reason:`${_dirLead} — tape ${vfLabel} disagrees, q+conv weak`,confidence:0,direction:dir,conviction,phase:'WATCHING'};
      }
      confidenceHaircut+=15;
      haircutReasons.push(`tape ${vfLabel}`);
    }
    if(kalshiDisagrees&&!kalshiStronglyDisagrees){
      // Mild Kalshi disagreement (40-45 / 55-60) — apply haircut, don't block
      confidenceHaircut+=10;
      haircutReasons.push(`kalshi ${_kPct}% disagrees`);
    }
    // All gates passed — Tara forms a call
    const _confBase=Math.min(95,Math.round(conviction*1.5+q*0.4));
    const _tapeBoost=tapeSuperStrong?15:tapeStronglyAgrees?8:0;
    const _kalshiBoost=kalshiStronglyAgrees?10:kalshiAgrees?5:0;
    // V5.7.7: Confluence boost. When tape, FGT, score, AND strike all agree, confidence
    //   gets a meaningful bump — this is the "this is the kind of call we want" reward.
    const _confluenceBoost=isSuperConfluent?12:isConfluent?6:0;
    // V5.6.8: Learning boost — when current regime+direction matches historically winning
    //   combos, add small confidence boost. When current matches historically losing combos,
    //   subtract. This is how Tara learns to PICK BETTER without sitting out more.
    // V6.5: SHORT SQUEEZE clamp. Evidence from V6.4.0 export: the learned UP bias in
    //   SHORT SQUEEZE is anti-correlated with outcomes (4 of 4 structural-led losses had
    //   "+5 learned UP preference" in the reason). The bias captures brief upward spikes
    //   that registered as wins before reversing. Clamp this regime to ±2 until we have
    //   enough confirmed-loss samples to trust the inverse direction.
    const _regDirKey=(analysis.regime||'UNKNOWN')+'|'+dir;
    const _rawLearnBoost=_learn?.multipliers?.regimeDirConfBoost?.[_regDirKey]||0;
    const _isSqueezeRegime=analysis.regime==='SHORT SQUEEZE'||analysis.regime==='LONG SQUEEZE';
    const _learnCap=_isSqueezeRegime?2:8;
    const _learnConfBoost=Math.max(-_learnCap,Math.min(_learnCap,_rawLearnBoost));
    // V5.7.8: Learned confluence-bucket boost. Bucket determined by current confluence state.
    //   Historical WR for this bucket informs the boost/haircut.
    // V6.0.1: rising-confluence is its own bucket — separate WR tracking from full confluence.
    // V6.0.7: tape-led is its own bucket too — separate WR tracking from full confluence.
    const _conflBucket=isStructuralLed?'structural-led':isSuperConfluent?'super-confluence':isConfluent?'confluence':isTapeLed?'tape-led':isRisingConfluence?'rising-confluence':'single-signal';
    const _learnConflBoost=Math.max(-8,Math.min(8,_learn?.multipliers?.confluenceConfBoost?.[_conflBucket]||0));
    // V6.5.3 BUGFIX: cap final confidence at 99. Without this cap, base (95) + tape boost
    //   (+10) + kalshi boost (+10) + confluence boost (+12) + learning boosts could
    //   exceed 100 — screenshot showed "123% confidence" which is mathematically impossible.
    //   Floor stays at 25 (a forming call is at least 25% confident).
    const _confidence=Math.max(25,Math.min(99,_confBase-confidenceHaircut+_tapeBoost+_kalshiBoost+_confluenceBoost+_learnConfBoost+_learnConflBoost));
    const _reasonParts=[`${conviction.toFixed(0)}pt ${dir} lean`,`FGT ${fgtAbs.toFixed(1)}/4`,`q${q}`];
    if(isSuperConfluent)_reasonParts.unshift(`SUPER-CONFLUENCE — tape+FGT+score+strike all ${dir}`);
    else if(isConfluent)_reasonParts.unshift(`CONFLUENCE — tape+FGT+score+strike all ${dir}`);
    else if(isTapeLed)_reasonParts.unshift(`TAPE-LED — tape ≥70% ${dir} across windows, fast-locking`);
    else if(isRisingConfluence)_reasonParts.unshift(`RISING — early entry, ${_risingScore}/4 leading ${dir}`);
    if(tapeSuperStrong)_reasonParts.push(`tape super-strong (${tapeBuyPct.toFixed(0)}%)`);
    else if(tapeStronglyAgrees)_reasonParts.push(`tape ${tapeBuyPct.toFixed(0)}%`);
    if(kalshiStronglyAgrees)_reasonParts.push(`kalshi ${_kPct}% confirms`);
    else if(kalshiAgrees)_reasonParts.push(`kalshi ${_kPct}% leans ${dir}`);
    if(haircutReasons.length>0)_reasonParts.push(`-${confidenceHaircut} for ${haircutReasons.join(' + ')}`);
    if(_learnConfBoost>0)_reasonParts.push(`+${_learnConfBoost} learned ${dir} preference in ${analysis.regime}`);
    else if(_learnConfBoost<0)_reasonParts.push(`${_learnConfBoost} historical ${dir} weakness in ${analysis.regime}`);
    if(_learnConflBoost>0)_reasonParts.push(`+${_learnConflBoost} from ${_conflBucket} history`);
    else if(_learnConflBoost<0)_reasonParts.push(`${_learnConflBoost} from ${_conflBucket} history`);
