        reason:`User force-override: gates bypassed, ${_forceDir} based on ${_forceDir==='UP'?Math.round(_post):Math.round(100-_post)}% posterior`,
        atSecondsLeft:timeState.minsRemaining*60+timeState.secsRemaining,
