    const _qFast=qualityGate?.score||0;
    const _hasAnyConfluence=(taraCall?._ctx?.isSuperConfluent)||(taraCall?._ctx?.isConfluent)||(taraCall?._ctx?.isTapeLed)||(taraCall?._ctx?.isRisingConfluence)||(taraCall?._ctx?.isStructuralLed);
